+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?|\
/g, '\
');
+}
+
+function redactPaths(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '');
+  }
+  return line.replace(/(?:[A-Za-z]:)?(?:[\\\\/][^\\s():]+)+/g, path => {
+    const parts = path.split(/[\\\\/]/);
+    return parts[parts.length - 1] || path;
+  });
+}
+
+function isInternal(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  const node = mode === 'node' || mode === 'node_and_superjson';
+  const superjson = mode === 'superjson' || mode === 'node_and_superjson';
+  return (node && line.includes('node:internal')) ||
+    (superjson && /src\\/(?:transformer|plainer|index)\\.ts/.test(line));
+}
+
+function processLines(stack: string, options: NormalizedErrorStackOptions, frames: boolean): string[] {
+  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  let lines = normalized.split(/\\r?\
/);
+  lines = lines.map((line, index) =>
+    index > 0 && options.trimLeadingWhitespace ? line.replace(/^\\s+/, '') : line
+  );
+  if (frames) {
+    lines = lines.filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+    lines = lines.map(line => redactPaths(line, options.redactPaths));
+  } else {
+    lines = lines.map(line => redactPaths(line, options.redactPaths));
+  }
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  if (!frames) lines = lines.filter((line, index) => index === 0 || !isInternal(line, options.stripInternalFrames));
+  return lines;
+}
